#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    vector<vector<long long>> w(n, vector<long long>(n));
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++) cin >> w[i][j];
    const long long INF = LLONG_MAX / 4;
    int full = (1 << n) - 1;
    vector<vector<long long>> dp(1 << n, vector<long long>(n, INF));
    dp[1][0] = 0;
    for (int mask = 1; mask <= full; mask++) {
        for (int i = 0; i < n; i++) {
            if (dp[mask][i] == INF) continue;
            if (!((mask >> i) & 1)) continue;
            for (int j = 0; j < n; j++) {
                if ((mask >> j) & 1) continue;
                if (w[i][j] == 0) continue;
                int nm = mask | (1 << j);
                dp[nm][j] = min(dp[nm][j], dp[mask][i] + w[i][j]);
            }
        }
    }
    long long ans = INF;
    for (int i = 0; i < n; i++) {
        if (dp[full][i] == INF) continue;
        if (w[i][0] == 0) continue;
        ans = min(ans, dp[full][i] + w[i][0]);
    }
    cout << ans << "\n";
    return 0;
}
